        private static async System.Threading.Tasks.Task<ConfigBuildResult> BuildFromConfigAsync(
            ThoughtSpot.RestApi.Sdk.ApiClientConfiguration config,
            System.Threading.CancellationToken cancellationToken)
        {
            var hasPassword  = config.Username is not null && config.Password  is not null;
            var hasSecretKey = config.Username is not null && config.SecretKey is not null;

            if (!hasPassword && !hasSecretKey && config.TokenProvider is null && config.BearerToken is null)
                throw new ArgumentException(
                    "Provide Username+Password, Username+SecretKey, a TokenProvider, or a BearerToken.");

            System.Func<System.Threading.CancellationToken, System.Threading.Tasks.Task<string>>? tokenProvider = null;

            // SocketsHttpHandler gives us per-instance ConnectTimeout, connection pooling,
            // and SSL control — matching Java OkHttp's three-way timeout model.
            var socketsHandler = new System.Net.Http.SocketsHttpHandler
            {
                ConnectTimeout             = config.ConnectTimeout,
                // Connection pool health: recycle idle connections after 90 s, cap lifetime at 10 min.
                PooledConnectionIdleTimeout  = System.TimeSpan.FromSeconds(90),
                PooledConnectionLifetime     = System.TimeSpan.FromMinutes(10),
            };
            if (config.IgnoreSslErrors)
                socketsHandler.SslOptions = new System.Net.Security.SslClientAuthenticationOptions
                {
                    RemoteCertificateValidationCallback = (_, _, _, _) => true,
                };

            var injectingHandler = new ThoughtSpot.RestApi.Sdk.Client.TokenInjectingHandler(
                async (ct) => tokenProvider is null ? string.Empty : await tokenProvider(ct),
                socketsHandler);

            // RefCountingHandler sits outermost so every request — including SSE streaming —
            // is tracked. ApplyConfigurationAsync waits for the count to reach zero before
            // disposing the old handler chain, preventing ObjectDisposedException mid-flight.
            var refCountingHandler = new ThoughtSpot.RestApi.Sdk.Client.RefCountingHandler(injectingHandler);

            // HttpClient.Timeout covers the full request lifecycle after connection.
            // Maps to Java's readTimeoutMillis + writeTimeoutMillis (we take the max of both).
            var effectiveTimeout = config.ReadTimeout.Ticks >= config.WriteTimeout.Ticks
                ? config.ReadTimeout : config.WriteTimeout;

            var httpClient = new System.Net.Http.HttpClient(refCountingHandler)
            {
                BaseAddress           = new Uri(config.Host.TrimEnd('/') + "/"),
                Timeout               = effectiveTimeout,
                DefaultRequestVersion = System.Net.HttpVersion.Version11,
                DefaultVersionPolicy  = System.Net.Http.HttpVersionPolicy.RequestVersionOrLower,
            };

            foreach (var (key, value) in config.DefaultHeaders)
                httpClient.DefaultRequestHeaders.TryAddWithoutValidation(key, value);

            var cfg = new ThoughtSpot.RestApi.Sdk.Client.Configuration { BasePath = config.Host.TrimEnd('/') };
            // ExecAsync creates a CancellationTokenSource from cfg.Timeout (default 100 s) and links
            // it with the caller's token — it fires before HttpClient.Timeout ever gets a chance.
            // Align cfg.Timeout with the same effective timeout we set on HttpClient so the two
            // mechanisms agree and the user's ReadTimeout/WriteTimeout is actually honoured.
            cfg.Timeout = effectiveTimeout;

            System.Net.Http.HttpClient? bareClient = null;
            System.Net.Http.SocketsHttpHandler? bareHandler = null;

            if (config.TokenProvider is not null)
            {
                tokenProvider = config.TokenProvider;
            }
            else if (config.BearerToken is not null)
            {
#pragma warning disable CS0618
                tokenProvider = _ => System.Threading.Tasks.Task.FromResult(config.BearerToken);
#pragma warning restore CS0618
            }
            else
            {
                var tokenRequest = new ThoughtSpot.RestApi.Sdk.Model.GetFullAccessTokenRequest(
                    username:          config.Username!,
                    password:          config.Password,
                    secretKey:         config.SecretKey,
                    validityTimeInSec: config.TokenValiditySeconds);

                // Use a bare HttpClient (no TokenInjectingHandler) for token fetch/refresh.
                // The injecting handler requires a token to already exist, creating a chicken-and-egg
                // problem on the initial fetch — the server receives "Authorization: Bearer " and returns 500.
                var bareSocketsHandler = new System.Net.Http.SocketsHttpHandler
                {
                    ConnectTimeout = config.ConnectTimeout,
                };
                if (config.IgnoreSslErrors)
                    bareSocketsHandler.SslOptions = new System.Net.Security.SslClientAuthenticationOptions
                    {
                        RemoteCertificateValidationCallback = (_, _, _, _) => true,
                    };
                bareHandler = bareSocketsHandler;
                bareClient = new System.Net.Http.HttpClient(bareSocketsHandler)
                {
                    BaseAddress = new Uri(config.Host.TrimEnd('/') + "/"),
                    Timeout     = System.TimeSpan.FromSeconds(30),
                };
                var authApi = new ThoughtSpot.RestApi.Sdk.Api.AuthenticationApi(bareClient, cfg, null);

                var first = await authApi.GetFullAccessTokenAsync(
                    tokenRequest, cancellationToken: cancellationToken);

                var cachedToken = first.VarToken
                    ?? throw new InvalidOperationException("Auth succeeded but token was null.");

                var expiresAt = DateTimeOffset.UtcNow.AddSeconds(config.TokenValiditySeconds - 30);

                // Guards against thundering-herd token refresh: if N concurrent requests all see
                // an expired token simultaneously, only the first to acquire the semaphore actually
                // fetches; the rest wait and then return the freshly-cached token on the re-check.
                var tokenSemaphore = new System.Threading.SemaphoreSlim(1, 1);

                // ThoughtSpot: token refresh retries on transient 502/503 with exponential back-off
                // (1s, 2s, 4s) so a momentarily flaky auth endpoint doesn't surface as an API error.
                tokenProvider = async (ct) =>
                {
                    if (DateTimeOffset.UtcNow < expiresAt)
                        return cachedToken;

                    await tokenSemaphore.WaitAsync(ct).ConfigureAwait(false);
                    try
                    {
                        // Double-check: another thread may have already refreshed while we waited.
                        if (DateTimeOffset.UtcNow < expiresAt)
                            return cachedToken;

                        Exception? lastEx = null;
                        for (int attempt = 0; attempt < 4; attempt++)
                        {
                            if (attempt > 0)
                                await System.Threading.Tasks.Task.Delay(TimeSpan.FromSeconds(Math.Pow(2, attempt - 1)), ct);
                            try
                            {
                                var refreshed = await authApi.GetFullAccessTokenAsync(tokenRequest, cancellationToken: ct);
                                cachedToken = refreshed.VarToken
                                    ?? throw new InvalidOperationException("Token refresh returned null.");
                                expiresAt = DateTimeOffset.UtcNow.AddSeconds(config.TokenValiditySeconds - 30);
                                return cachedToken;
                            }
                            catch (ApiException ex) when (ex.ErrorCode is 429 or 500 or 502 or 503)
                            {
                                lastEx = ex;
                            }
                        }
                        throw new InvalidOperationException("Token refresh failed after 4 attempts.", lastEx);
                    }
                    finally { tokenSemaphore.Release(); }
                };
            }

            return new ConfigBuildResult(httpClient, cfg, bareClient, bareHandler, refCountingHandler);
        }

